<?php

// O código Base64 otimizado da imagem Oravel ( image_2.png )
$base64String = '';

// Decodifica a string Base64 para dados binários de imagem
$imageData = base64_decode($base64String);

if ($imageData === false) {
    die("Erro: Falha ao decodificar a string Base64.\n");
}

// Define o caminho de destino
$targetPath = 'public/icon.png';

// Salva os dados binários no arquivo icon.png
$result = file_put_contents($targetPath, $imageData);

if ($result === false) {
    die("Erro: Não foi possível salvar o arquivo em $targetPath. Verifique as permissões da pasta.\n");
}

echo "Sucesso! O ícone foi gerado em: $targetPath (" . $result . " bytes)\n";

?>
